// --- RabbitMQ Consumer Logic ---
async function startConsumer() {
    try {
        connection = await amqp.connect(RABBITMQ_URL);
        connection.on('error', (err) => {
            console.error('[AMQP] connection error:', err.message);
            // Attempt to reconnect on connection errors
            setTimeout(startConsumer, 5000);
        });
        connection.on('close', () => {
            console.error('[AMQP] connection closed, attempting to reconnect...');
            setTimeout(startConsumer, 5000);
        });

        channel = await connection.createChannel();
        await channel.assertQueue(QUEUE_NAME, {
            durable: true // Ensure the queue survives broker restarts
        });
        channel.prefetch(1); // Process one message at a time to prevent overwhelming the consumer

        console.log(`[*] Waiting for messages in ${QUEUE_NAME}. To exit press CTRL+C`);

        channel.consume(QUEUE_NAME, async (msg) => {
            if (msg === null) {
                console.warn('[AMQP] Consumer cancelled by broker.');
                return;
            }

            let messageContent;
            try {
                // Parse the message content as JSON
                messageContent = JSON.parse(msg.content.toString());
                console.log(`[x] Received message: ${JSON.stringify(messageContent)}`);

                const { type, payload } = messageContent;

                // Check if the message type is known and has a handler
                if (!type || !messageHandlers[type]) {
                    console.warn(`[!] Unknown or missing message type: '${type}'. Message will be rejected.`);
                    // Acknowledge negative (nack), don't requeue (false, false)
                    // This often sends the message to a Dead-Letter Queue if configured.
                    channel.nack(msg, false, false);
                    return;
                }

                try {
                    // Execute the corresponding handler function
                    await messageHandlers[type](payload);
                    // Acknowledge the message after successful processing
                    channel.ack(msg);
                    console.log(`[ACK] Message of type '${type}' processed and acknowledged.`);
                } catch (handlerError) {
                    console.error(`[!] Error processing message type '${type}':`, handlerError);
                    // Acknowledge negative (nack), and requeue the message (false, true)
                    // This allows another consumer (or this one after a delay) to retry.
                    channel.nack(msg, false, true);
                }

            } catch (parseError) {
                // Handle JSON parsing errors
                console.error('[!] Failed to parse message content as JSON:', msg.content.toString(), parseError);
                // Nack the message and don't requeue if it's malformed JSON
                channel.nack(msg, false, false);
            }
        }, {
            noAck: false // We will manually acknowledge messages
        });

    } catch (error) {
        console.error('[AMQP] Failed to connect or setup consumer:', error.message);
        // Retry connection after a delay if initial setup fails
        setTimeout(startConsumer, 5000);
    }
}

// --- Graceful Shutdown ---
async function closeConnection() {
    console.log('\n[AMQP] Closing RabbitMQ connection...');
    if (channel) {
        try {
            await channel.close();
            console.log('[AMQP] Channel closed.');
        } catch (err) {
            console.error('[AMQP] Error closing channel:', err.message);
        }
    }
    if (connection) {
        try {
            await connection.close();
            console.log('[AMQP] Connection closed.');
        } catch (err) {
            console.error('[AMQP] Error closing connection:', err.message);
        }
    }
    process.exit(0);
}

// Listen for termination signals to close the connection gracefully
process.on('SIGINT', closeConnection);
process.on('SIGTERM', closeConnection);

// Start the consumer microservice
startConsumer();

